static public function getObstaclesForFacet($facetName){
	$ret=[];
	foreach(self::$cards as $key=>$card){
		if ($facetName=="all"||T13Types::contains($card['Facet'], $facetName)){
			array_unshift($ret,self::$obstacles[$key]);
		}
	}
	return $ret;
}

