		$sig =array_shift($cardlist);
		$significator=self::getSignificator($sig, 'scene');
		$ret.=self::getCard($sig, 'jsvg', 1, 1);
		$ret.=$significator['Html'];
		//Beat Type
		$beat = array_shift($cardlist);
		$ret.= self::getCardAspectHTML($beat,'Beat_Type');
		return $ret.'</section>';
	}
